import ctypes
import logging
import os
import struct
import sys
import winreg
import zlib
from ctypes import POINTER, WinDLL, byref, c_int, create_unicode_buffer, sizeof, windll, wintypes
from pathlib import Path
from tkinter import *
from tkinter import ttk
from typing import TYPE_CHECKING, ClassVar, Literal, overload

import chardet
import requests
import win32api
from packaging.version import InvalidVersion, Version
from psutil import Process

import sv_ttk
from globals import APP_VERSION, COLOR_DEFAULT, FONT, FONT_SMALL, NEXUS_LINK
from mod_manager_info import ModManagerInfo

if TYPE_CHECKING:
	import io
	from collections.abc import Generator, Sequence
	from ctypes import _CDataType  # pyright: ignore[reportPrivateUsage] # noqa: PLC2701

	from enums import CSIDL
	from helpers import DLLInfo

logger = logging.getLogger(__name__)

DONT_RESOLVE_DLL_REFERENCES = 0x00000001
HTTP_OK = 200
KEY_CTRL = 12

win11_24h2 = sys.getwindowsversion().build >= 26100

type Fields = Sequence[tuple[str, type[_CDataType]] | tuple[str, type[_CDataType], int]]

class F4SEPluginVersionData(ctypes.Structure):
	_fields_: ClassVar[Fields] = [
		("dataVersion", ctypes.c_uint32),
		("pluginVersion", ctypes.c_uint32),
		("name", ctypes.c_char * 256),
		("author", ctypes.c_char * 256),
		("addressIndependence", ctypes.c_uint32),
		("structureIndependence", ctypes.c_uint32),
		("compatibleVersions", ctypes.c_uint32 * 16),
		("seVersionRequired", ctypes.c_uint32),
		("reservedNonBreaking", ctypes.c_uint32),
		("reservedBreaking", ctypes.c_uint32),
		("reserved", ctypes.c_uint8 * 512),
	]

def rglob(path: Path, ext: str) -> Generator[Path]:
	if not win11_24h2:
		yield from path.rglob(f"*.{ext}")
		return

	ext = ext.lower()
	for root, _, files in path.walk():
		for file in files:
			if file.lower().endswith(f"*.{ext}"):
				yield root / file


def is_file(path: Path) -> bool:
	if not win11_24h2:
		return path.is_file()

	try:
		with path.open(encoding="utf-8"):
			pass
	except FileNotFoundError:
		return False
	except PermissionError:
		# Probably a folder
		try:
			_ = next(path.iterdir(), None)
		except NotADirectoryError:
			# Was a file with actual PermissionError
			return True
		except OSError:
			pass
		return False
	return True


def is_dir(path: Path) -> bool:
	if not win11_24h2:
		return path.is_dir()

	try:
		_ = next(path.iterdir(), None)
	except (NotADirectoryError, FileNotFoundError):
		return False
	return True


def exists(path: Path) -> bool:
	if not win11_24h2:
		return path.exists()

	# Files
	try:
		with path.open(encoding="utf-8"):
			return True
	except FileNotFoundError:
		return False
	except PermissionError:
		# Probably a folder, check below
		pass

	# Folders
	try:
		_ = next(path.iterdir(), None)
	except (PermissionError, NotADirectoryError):
		# PermissionError: Actual folder but no permission
		# NotADirectoryError: Was a file with actual PermissionError
		pass
	except OSError:
		return False
	return True


def read_text_encoded(file_path: Path) -> tuple[str, str]:
	file_bytes = file_path.read_bytes()
	encoding = chardet.detect(file_bytes)["encoding"] or "utf-8"
	return file_bytes.decode(encoding), encoding


def load_font(font_path: str) -> None:
	# https://learn.microsoft.com/en-us/windows/win32/api/wingdi/nf-wingdi-addfontresourceexw
	# FR_PRIVATE = 0x10
	# FR_NOT_ENUM = 0x20
	buffer = create_unicode_buffer(font_path)
	windll.gdi32.AddFontResourceExW(byref(buffer), 0x10, 0)


def get_environment_path(location: CSIDL) -> Path:
	buf = create_unicode_buffer(wintypes.MAX_PATH)
	windll.shell32.SHGetFolderPathW(None, location, None, 0, buf)
	path = Path(buf.value)
	if not is_dir(path):
		msg = f"Folder does not exist:\n{path}"
		raise FileNotFoundError(msg)
	return path


def is_fo4_dir(path: Path) -> bool:
	return is_dir(path) and is_file(path / "Fallout4.exe")


def find_mod_manager() -> ModManagerInfo | None:
	pid = os.getppid()
	proc: Process | None = Process(pid)

	managers = {"ModOrganizer.exe", "Vortex.exe"}
	manager = None

	for _ in range(8):
		if proc is None:
			break

		with proc.oneshot():
			if proc.name() in managers:
				manager_path = Path(proc.exe())
				manager = "Mod Organizer" if proc.name() == "ModOrganizer.exe" else "Vortex"
				ver = get_file_version(manager_path)
				manager_version = Version(".".join(str(n) for n in ver[:3])) if ver else Version("0.0.0")
				return ModManagerInfo(manager, manager_path, manager_version)
			proc = proc.parent()
	return None


def get_asset_path(relative_path: str) -> Path:
	# PyInstaller EXEs extract to a temp folder and store the path in sys._MEIPASS
	base_path = Path(str(getattr(sys, "_MEIPASS", False) or "."))
	return base_path / "assets" / relative_path


def block_text_input(event: Event[Text]) -> str | None:
	# Block all input except CTRL+A / CTRL+C
	if event.state == KEY_CTRL and event.keysym in "AC":
		return None
	return "break"


def get_file_version(path: Path) -> tuple[int, int, int, int] | None:
	try:
		info = win32api.GetFileVersionInfo(str(path), "\\")
	except:
		return None
	ms = info["FileVersionMS"]
	ls = info["FileVersionLS"]
	return (
		win32api.HIWORD(ms),
		win32api.LOWORD(ms),
		win32api.HIWORD(ls),
		win32api.LOWORD(ls),
	)


def get_crc32(file_path: Path, chunk_size: int = 65536, max_chunks: int | None = None, *, skip_ba2_header: bool = False) -> str:
	with file_path.open("rb") as f:
		checksum = 0
		chunks = 0
		if skip_ba2_header:
			f.seek(12)
		while chunk := f.read(chunk_size):
			checksum = zlib.crc32(chunk, checksum)
			if max_chunks is not None:
				chunks += 1
				if chunks >= max_chunks:
					break
	return f"{checksum:08X}"


def parse_dll(file_path: Path) -> DLLInfo:
	dll = WinDLL(str(file_path), winmode=DONT_RESOLVE_DLL_REFERENCES)
	dll_info: DLLInfo = {
		"IsF4SE": hasattr(dll, "F4SEPlugin_Load") or hasattr(dll, "F4SEPlugin_Preload"),
		"SupportsOG": hasattr(dll, "F4SEPlugin_Query"),
		"SupportsNGAE": hasattr(dll, "F4SEPlugin_Version"),
		"SupportsNG": None,
		"SupportsAE": None,
	}

	if dll_info["SupportsNGAE"]:
		sym = ctypes.cast(
			dll.F4SEPlugin_Version,
			POINTER(F4SEPluginVersionData),
		)
		v = sym.contents
		if 0x010A3D40 in v.compatibleVersions or 0x010A3D80 in v.compatibleVersions:
			dll_info["SupportsNG"] = True

		if any(n > 0x010B0890 for n in v.compatibleVersions):
			dll_info["SupportsAE"] = True

	return dll_info


def ver_to_str(version: str | tuple[int, int, int, int]) -> str:
	if isinstance(version, str):
		return version

	return ".".join(map(str, version))


def get_registry_value(key: int, subkey: str, value_name: str) -> str | None:
	try:
		with winreg.OpenKey(key, subkey) as reg_handle:
			value, value_type = winreg.QueryValueEx(reg_handle, value_name)

		if value and value_type == winreg.REG_SZ and isinstance(value, str):
			return value

	except OSError:
		pass

	return None


def copy_text(widget: ttk.Widget, text: str) -> None:
	widget.clipboard_clear()
	widget.clipboard_append(text)


def copy_text_button(button: ttk.Button, text: str) -> None:
	button.master.clipboard_clear()
	button.master.clipboard_append(text)
	original_text = button.cget("text")
	button.config(text="Copied!", state=DISABLED)
	button.master.after(3000, lambda: button.config(text=original_text, state=NORMAL))


def add_separator(master: Misc, orient: Literal["horizontal", "vertical"], column: int, row: int, span: int) -> None:
	separator = ttk.Separator(master, orient=orient)
	if orient == HORIZONTAL:
		separator.grid(column=column, row=row, columnspan=span, padx=10, pady=10, ipady=1, sticky=EW)
	else:
		separator.grid(column=column, row=row, rowspan=span, padx=10, pady=10, ipadx=1, sticky=NS)


def set_titlebar_style(window: Misc) -> None:
	window.update()
	hwnd = windll.user32.GetParent(window.winfo_id())
	windll.dwmapi.DwmSetWindowAttribute(hwnd, 19, byref(c_int(1)), sizeof(c_int))
	windll.dwmapi.DwmSetWindowAttribute(hwnd, 20, byref(c_int(1)), sizeof(c_int))


def set_theme(win: Tk) -> None:
	set_titlebar_style(win)
	sv_ttk.apply_dark_theme()
	style = ttk.Style(win)

	# Remove blue dotted line from focused tab
	# fmt: off
	style.layout(
		"Tab", [("Notebook.tab", {
			"sticky": NSEW,
			"children": [("Notebook.padding", {
				"side": TOP,
				"sticky": NSEW,
				"children": [("Notebook.label", {
					"side": TOP,
					"sticky": "",
				})],
			})],
		})],
	)
	# fmt: on
	# style.configure("TNotebook.Tab", padding=padding)
	style.configure("Tab", font=FONT, foreground=COLOR_DEFAULT)
	style.configure("TButton", font=FONT_SMALL, foreground=COLOR_DEFAULT)
	style.configure("TCheckbutton", font=FONT_SMALL, foreground=COLOR_DEFAULT)
	style.configure("TRadiobutton", font=FONT_SMALL, foreground=COLOR_DEFAULT)
	style.configure("TLabelframe.Label", font=FONT_SMALL, foreground=COLOR_DEFAULT)
	style.configure("Treeview", font=FONT_SMALL, foreground=COLOR_DEFAULT)
	style.configure("Heading", font=FONT_SMALL, foreground=COLOR_DEFAULT)
	style.configure("Update.TFrame", background="pale green")


def check_for_update_nexus() -> str | None:
	logger.debug("Update Check : Nexus Mods")
	try:
		response = requests.get(NEXUS_LINK, timeout=5, stream=True)
		if response.status_code == HTTP_OK:
			use_next = False
			version_line = None
			for line in response.iter_lines(decode_unicode=True):
				if TYPE_CHECKING:
					assert isinstance(line, str)
				if use_next:
					version_line = line.rsplit('"', 2)
					response.close()
					break

				if line.lstrip().startswith('<meta property="twitter:label1" content="Version"'):
					use_next = True
					continue

			if not version_line:
				logger.error("Update Check : Nexus Mods : Failed")
				return None

			latest_version = version_line[1]
			if Version(latest_version) > Version(str(APP_VERSION)):
				logger.info("Update Check : Nexus Mods : Update Available : v%s", latest_version)  # TODO: test variable
				return latest_version
	except (requests.RequestException, InvalidVersion, IndexError):
		logger.exception("Update Check : Nexus Mods : Failed")  # TODO: Reasons
		return None

	logger.debug("Update Check : Nexus Mods : No Updates")
	return None


def check_for_update_github() -> str | None:
	logger.debug("Update Check : GitHub")
	url = "https://api.github.com/repos/wxMichael/Collective-Modding-Toolkit/releases/latest"
	headers = {
		"Accept": "application/vnd.github+json",
		"X-GitHub-Api-Version": "2022-11-28",
	}
	try:
		response = requests.get(url, headers=headers, timeout=5)
	except requests.RequestException:
		logger.exception("Update Check : GitHub : Failed")
		return None

	if response.status_code == HTTP_OK:
		try:
			release_data = response.json()
			latest_version = str(release_data["tag_name"])
			if Version(latest_version) > Version(str(APP_VERSION)):
				logger.info("Update Check : GitHub : Update Available : v%s", latest_version)
				return latest_version
		except (requests.JSONDecodeError, InvalidVersion):
			logger.exception("Update Check : GitHub : Failed")
			return None

	logger.debug("Update Check : GitHub : No Updates")
	return None


@overload
def read_uint(source: io.BufferedIOBase) -> int: ...
@overload
def read_uint(source: io.BufferedIOBase, count: int) -> tuple[int, ...]: ...
def read_uint(source: io.BufferedIOBase, count: int = 1) -> int | tuple[int, ...]:
	if count < 1:
		raise ValueError
	uints: tuple[int, ...] = struct.unpack(f"<{count}I", source.read(count * 4))
	if len(uints) != count:
		raise SyntaxError
	if count == 1:
		return uints[0]
	return uints

//! Pure domain contracts for Fallout 4 discovery state.
//!
//! These types deliberately do not touch the filesystem, registry, processes, or
//! Slint. Later platform adapters can populate them from real discovery work
//! while tests can construct them from inline paths and values.

use std::{
    collections::BTreeMap,
    fmt,
    path::{Path, PathBuf},
};

/// Reference game identifier used by the original Python `GameInfo` object.
pub const FALLOUT4_GAME_ID: &str = "Fallout4";
/// Executable name used to recognize a Fallout 4 installation directory.
pub const FALLOUT4_EXECUTABLE: &str = "Fallout4.exe";
/// Reference-compatible message shown when no valid game path is available.
pub const FALLOUT4_NOT_FOUND_MESSAGE: &str = "A Fallout 4 installation could not be found.";
/// Reference-compatible loading error used by Overview, F4SE, and Scanner paths.
pub const DATA_FOLDER_NOT_FOUND_MESSAGE: &str = "Data folder not found";
/// Reference-compatible F4SE loading error prefix.
pub const F4SE_PLUGINS_NOT_FOUND_MESSAGE: &str = "Data/F4SE/Plugins folder not found";

/// Semantic version used for tools and discovered executables.
///
/// The reference app uses Python's `packaging.version.Version` for manager
/// versions. The current Rust domain contract only needs a stable three-part
/// semantic version plus a `0.0.0` fallback for unknown executable metadata.
#[derive(Debug, Default, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub struct SemanticVersion {
    /// Major version component.
    pub major: u64,
    /// Minor version component.
    pub minor: u64,
    /// Patch version component.
    pub patch: u64,
}

impl SemanticVersion {
    /// Creates a semantic version from major, minor, and patch components.
    pub const fn new(major: u64, minor: u64, patch: u64) -> Self {
        Self {
            major,
            minor,
            patch,
        }
    }

    /// Returns the reference-compatible fallback used when file metadata is unavailable.
    pub const fn zero() -> Self {
        Self::new(0, 0, 0)
    }
}

impl fmt::Display for SemanticVersion {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(formatter, "{}.{}.{}", self.major, self.minor, self.patch)
    }
}

/// Reference install-type labels from `CMT/src/enums.py`.
#[derive(Debug, Default, Clone, Copy, PartialEq, Eq, Hash)]
pub enum Fallout4InstallType {
    /// Reference `Obsolete` state.
    Obsolete,
    /// Reference `Old-Gen` state.
    OldGen,
    /// Reference `Down-Grade` state.
    DownGrade,
    /// Reference `Next-Gen` state.
    NextGen,
    /// Reference `Anniversary` state.
    Anniversary,
    /// Reference `Next-Gen & Anniversary` state.
    NextGenAnniversary,
    /// Reference default state before binary classification runs.
    #[default]
    Unknown,
    /// Reference state used when a base executable is absent.
    NotFound,
}

impl Fallout4InstallType {
    /// Returns the exact user-facing label used by the reference enum.
    pub const fn as_reference_str(self) -> &'static str {
        match self {
            Self::Obsolete => "Obsolete",
            Self::OldGen => "Old-Gen",
            Self::DownGrade => "Down-Grade",
            Self::NextGen => "Next-Gen",
            Self::Anniversary => "Anniversary",
            Self::NextGenAnniversary => "Next-Gen & Anniversary",
            Self::Unknown => "Unknown",
            Self::NotFound => "Not Found",
        }
    }
}

impl fmt::Display for Fallout4InstallType {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(self.as_reference_str())
    }
}

/// Pure representation of a discovered Fallout 4 installation.
///
/// `game_path` is the only required path. `data_path` and `f4se_plugins_path`
/// remain optional because the reference app can have a valid game executable
/// while Data or Data/F4SE/Plugins are absent, producing recoverable tab-level
/// loading messages instead of invalidating the installation itself.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Fallout4Installation {
    /// Directory containing `Fallout4.exe`.
    pub game_path: PathBuf,
    /// Optional `Data` directory if a platform adapter has confirmed one.
    pub data_path: Option<PathBuf>,
    /// Optional `Data/F4SE/Plugins` directory if confirmed.
    pub f4se_plugins_path: Option<PathBuf>,
    /// Binary classification state for the current install.
    pub install_type: Fallout4InstallType,
    /// Archive records observed by later scanner/overview workflows.
    pub archives: Vec<ArchiveRecord>,
    /// Plugin/module records observed by later scanner/overview workflows.
    pub modules: Vec<ModuleRecord>,
    /// Parsed Fallout 4 INI state from the user profile.
    pub ini_files: Fallout4IniFiles,
}

impl Fallout4Installation {
    /// Creates an installation with only the required game path.
    ///
    /// This constructor performs no existence checks and intentionally does not
    /// infer `Data` or `F4SE` paths, preserving the Phase 3 contract that those
    /// derived paths are optional facts supplied by discovery adapters.
    pub fn new(game_path: impl Into<PathBuf>) -> Self {
        Self {
            game_path: game_path.into(),
            data_path: None,
            f4se_plugins_path: None,
            install_type: Fallout4InstallType::Unknown,
            archives: Vec::new(),
            modules: Vec::new(),
            ini_files: Fallout4IniFiles::default(),
        }
    }

    /// Creates an installation with optional derived paths supplied by an adapter.
    pub fn with_optional_paths(
        game_path: impl Into<PathBuf>,
        data_path: Option<impl Into<PathBuf>>,
        f4se_plugins_path: Option<impl Into<PathBuf>>,
    ) -> Self {
        let mut installation = Self::new(game_path);
        installation.data_path = data_path.map(Into::into);
        installation.f4se_plugins_path = f4se_plugins_path.map(Into::into);
        installation
    }

    /// Returns the reference game identifier for this installation contract.
    pub const fn game_id(&self) -> &'static str {
        FALLOUT4_GAME_ID
    }

    /// Returns whether an adapter has confirmed a Data directory.
    pub const fn has_data_path(&self) -> bool {
        self.data_path.is_some()
    }

    /// Returns whether an adapter has confirmed a Data/F4SE/Plugins directory.
    pub const fn has_f4se_plugins_path(&self) -> bool {
        self.f4se_plugins_path.is_some()
    }
}

/// Archive file format magic recognized by the reference scanner.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum ArchiveFormat {
    /// General BA2 archive (`GNRL`).
    General,
    /// DirectX 10 texture BA2 archive (`DX10`).
    DirectX10,
    /// Any other archive format marker retained for diagnostics.
    Unknown(String),
}

impl ArchiveFormat {
    /// Returns the reference byte marker text when the format is known.
    pub const fn as_reference_magic(&self) -> Option<&'static str> {
        match self {
            Self::General => Some("GNRL"),
            Self::DirectX10 => Some("DX10"),
            Self::Unknown(_) => None,
        }
    }
}

/// BA2 version classes used by the archive overview and patcher workflows.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum ArchiveVersion {
    /// v1, required by Old-Gen Fallout 4 and accepted by all versions.
    OldGen,
    /// v7, initial Next-Gen archive version.
    NextGen7,
    /// v8, current Next-Gen archive version.
    NextGen8,
    /// Any other version byte retained for diagnostics.
    Unknown(u32),
}

impl ArchiveVersion {
    /// Converts the typed archive version into the numeric value in the BA2 header.
    pub const fn as_header_value(self) -> u32 {
        match self {
            Self::OldGen => 1,
            Self::NextGen7 => 7,
            Self::NextGen8 => 8,
            Self::Unknown(value) => value,
        }
    }
}

/// Single archive record carried by scanner and overview workflows.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ArchiveRecord {
    /// Archive path as discovered by a platform/scanner adapter.
    pub path: PathBuf,
    /// Parsed archive format marker.
    pub format: ArchiveFormat,
    /// Parsed archive version.
    pub version: ArchiveVersion,
    /// Whether later enablement parsing found this archive active.
    pub enabled: bool,
    /// Whether the scanner could read enough bytes to classify the archive.
    pub readable: bool,
}

impl ArchiveRecord {
    /// Creates a readable archive record with an explicit enabled state.
    pub fn new(
        path: impl Into<PathBuf>,
        format: ArchiveFormat,
        version: ArchiveVersion,
        enabled: bool,
    ) -> Self {
        Self {
            path: path.into(),
            format,
            version,
            enabled,
            readable: true,
        }
    }

    /// Creates an unreadable archive record while preserving its path.
    pub fn unreadable(path: impl Into<PathBuf>) -> Self {
        Self {
            path: path.into(),
            format: ArchiveFormat::Unknown(String::new()),
            version: ArchiveVersion::Unknown(0),
            enabled: false,
            readable: false,
        }
    }
}

/// Module/header classes used for ESP/ESM/ESL overview state.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub enum ModuleHeaderVersion {
    /// Reference-supported HEDR v0.95.
    Version095,
    /// Reference-supported HEDR v1.00.
    Version100,
    /// Any unsupported header value retained as text for diagnostics.
    Unknown(String),
}

impl ModuleHeaderVersion {
    /// Returns the reference display text for known module header versions.
    pub const fn as_reference_str(&self) -> Option<&'static str> {
        match self {
            Self::Version095 => Some("0.95"),
            Self::Version100 => Some("1.00"),
            Self::Unknown(_) => None,
        }
    }
}

/// Plugin/module kind inferred from flags and extension.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum ModuleKind {
    /// Full plugin/module.
    Full,
    /// Light plugin/module, matching the reference light flag grouping.
    Light,
}

/// Single plugin/module record carried by scanner and overview workflows.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ModuleRecord {
    /// Module path as discovered by a platform/scanner adapter.
    pub path: PathBuf,
    /// Full or light module classification.
    pub kind: ModuleKind,
    /// Parsed HEDR/header version.
    pub header_version: ModuleHeaderVersion,
    /// Whether plugin enablement parsing found this module active.
    pub enabled: bool,
    /// Whether the scanner could read enough bytes to classify the module.
    pub readable: bool,
}

impl ModuleRecord {
    /// Creates a readable module record with explicit enablement state.
    pub fn new(
        path: impl Into<PathBuf>,
        kind: ModuleKind,
        header_version: ModuleHeaderVersion,
        enabled: bool,
    ) -> Self {
        Self {
            path: path.into(),
            kind,
            header_version,
            enabled,
            readable: true,
        }
    }

    /// Creates an unreadable module record while preserving its path.
    pub fn unreadable(path: impl Into<PathBuf>) -> Self {
        Self {
            path: path.into(),
            kind: ModuleKind::Full,
            header_version: ModuleHeaderVersion::Unknown(String::new()),
            enabled: false,
            readable: false,
        }
    }
}

/// Parsed key/value contents for a single Fallout 4 INI file.
#[derive(Debug, Default, Clone, PartialEq, Eq)]
pub struct IniDocument {
    /// Optional source path used for diagnostics and later reload operations.
    pub source_path: Option<PathBuf>,
    /// Lowercase section names mapped to lowercase setting keys and raw values.
    pub sections: BTreeMap<String, BTreeMap<String, String>>,
}

impl IniDocument {
    /// Creates an empty INI document with an optional source path.
    pub fn new(source_path: Option<impl Into<PathBuf>>) -> Self {
        Self {
            source_path: source_path.map(Into::into),
            sections: BTreeMap::new(),
        }
    }

    /// Returns a setting value by already-normalized section and key names.
    pub fn get(&self, section: &str, key: &str) -> Option<&str> {
        self.sections
            .get(section)
            .and_then(|settings| settings.get(key))
            .map(String::as_str)
    }
}

/// Parsed Fallout 4 INI documents used by overview/scanner behavior.
#[derive(Debug, Default, Clone, PartialEq, Eq)]
pub struct Fallout4IniFiles {
    /// Parsed `Fallout4.ini` settings.
    pub fallout4: IniDocument,
    /// Parsed `Fallout4Prefs.ini` settings.
    pub prefs: IniDocument,
    /// Parsed `Fallout4Custom.ini` settings.
    pub custom: IniDocument,
}

/// Recoverable discovery failure with a safe user-facing message.
///
/// Raw OS details should be kept in `diagnostic` unless a reference message
/// intentionally includes a path, such as the invalid registry path and missing
/// environment-folder cases.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct DiscoveryError {
    /// Typed failure category.
    pub kind: DiscoveryErrorKind,
    /// Non-user-facing detail for logs or diagnostics.
    pub diagnostic: Option<String>,
}

impl DiscoveryError {
    /// Creates the generic reference-compatible Fallout 4 not-found error.
    pub fn fallout4_not_found(diagnostic: impl Into<Option<String>>) -> Self {
        Self {
            kind: DiscoveryErrorKind::Fallout4NotFound,
            diagnostic: diagnostic.into(),
        }
    }

    /// Creates the invalid-registry-path error whose reference text includes the path.
    pub fn invalid_registry_path(path: impl Into<PathBuf>) -> Self {
        Self {
            kind: DiscoveryErrorKind::InvalidRegistryPath { path: path.into() },
            diagnostic: None,
        }
    }

    /// Creates the environment-folder missing error whose reference text includes the path.
    pub fn environment_folder_missing(path: impl Into<PathBuf>) -> Self {
        Self {
            kind: DiscoveryErrorKind::EnvironmentFolderMissing { path: path.into() },
            diagnostic: None,
        }
    }

    /// Creates the reference-compatible Data folder loading error.
    pub fn data_folder_not_found() -> Self {
        Self {
            kind: DiscoveryErrorKind::DataFolderNotFound,
            diagnostic: None,
        }
    }

    /// Creates the reference-compatible F4SE plugins loading error.
    pub fn f4se_plugins_folder_not_found(mod_manager_detected: bool) -> Self {
        Self {
            kind: DiscoveryErrorKind::F4sePluginsFolderNotFound {
                mod_manager_detected,
            },
            diagnostic: None,
        }
    }

    /// Returns the message safe to show to users.
    pub fn user_message(&self) -> String {
        match &self.kind {
            DiscoveryErrorKind::Fallout4NotFound => FALLOUT4_NOT_FOUND_MESSAGE.to_owned(),
            DiscoveryErrorKind::InvalidRegistryPath { path } => format!(
                "A Fallout 4 installation could not be found.\n\nThe path set in your registry is:\n{}\n\nIf this is not correct, please run the Fallout 4 Launcher to correct it.",
                display_path(path)
            ),
            DiscoveryErrorKind::EnvironmentFolderMissing { path } => {
                format!("Folder does not exist:\n{}", display_path(path))
            }
            DiscoveryErrorKind::DataFolderNotFound => DATA_FOLDER_NOT_FOUND_MESSAGE.to_owned(),
            DiscoveryErrorKind::F4sePluginsFolderNotFound {
                mod_manager_detected,
            } => {
                if *mod_manager_detected {
                    F4SE_PLUGINS_NOT_FOUND_MESSAGE.to_owned()
                } else {
                    format!("{F4SE_PLUGINS_NOT_FOUND_MESSAGE}\nTry launching via your mod manager.")
                }
            }
        }
    }

    /// Returns whether the failure should be handled without terminating discovery orchestration.
    pub const fn is_recoverable(&self) -> bool {
        true
    }

    /// Returns whether resolving this error requires a manual file-picker UI.
    ///
    /// Phase 3 adapters should report the error and let higher layers decide how
    /// to recover; the domain contract itself does not mandate the reference
    /// Tkinter file-picker prompt.
    pub const fn requires_manual_file_picker(&self) -> bool {
        false
    }
}

impl fmt::Display for DiscoveryError {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(&self.user_message())
    }
}

impl std::error::Error for DiscoveryError {}

/// Typed discovery failure categories.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum DiscoveryErrorKind {
    /// No valid Fallout 4 installation path could be found.
    Fallout4NotFound,
    /// A registry value was present but did not identify a valid Fallout 4 directory.
    InvalidRegistryPath {
        /// Registry path text intentionally included by the reference user message.
        path: PathBuf,
    },
    /// A required Windows known folder did not exist.
    EnvironmentFolderMissing {
        /// Missing folder path intentionally included by the reference helper.
        path: PathBuf,
    },
    /// A tab/workflow required Data but discovery did not provide it.
    DataFolderNotFound,
    /// A tab/workflow required Data/F4SE/Plugins but discovery did not provide it.
    F4sePluginsFolderNotFound {
        /// Whether a mod manager was already detected, matching the reference hint behavior.
        mod_manager_detected: bool,
    },
}

fn display_path(path: &Path) -> String {
    path.display().to_string()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn fallout4_installation_does_not_require_data_or_f4se_paths() {
        let installation = Fallout4Installation::new("C:/Games/Fallout 4");

        assert_eq!(installation.game_id(), "Fallout4");
        assert_eq!(installation.game_path, PathBuf::from("C:/Games/Fallout 4"));
        assert_eq!(installation.data_path, None);
        assert_eq!(installation.f4se_plugins_path, None);
        assert!(!installation.has_data_path());
        assert!(!installation.has_f4se_plugins_path());
        assert_eq!(installation.install_type.as_reference_str(), "Unknown");
    }

    #[test]
    fn fallout4_installation_can_carry_optional_derived_paths() {
        let installation = Fallout4Installation::with_optional_paths(
            "C:/Games/Fallout 4",
            Some("C:/Games/Fallout 4/Data"),
            Some("C:/Games/Fallout 4/Data/F4SE/Plugins"),
        );

        assert_eq!(
            installation.data_path.as_deref(),
            Some(Path::new("C:/Games/Fallout 4/Data"))
        );
        assert_eq!(
            installation.f4se_plugins_path.as_deref(),
            Some(Path::new("C:/Games/Fallout 4/Data/F4SE/Plugins"))
        );
        assert!(installation.has_data_path());
        assert!(installation.has_f4se_plugins_path());
    }

    #[test]
    fn archive_module_and_ini_records_are_pure_domain_state() {
        let mut installation = Fallout4Installation::new("C:/Games/Fallout 4");
        installation.archives.push(ArchiveRecord::new(
            "C:/Games/Fallout 4/Data/Fallout4 - Textures.ba2",
            ArchiveFormat::DirectX10,
            ArchiveVersion::NextGen8,
            true,
        ));
        installation.modules.push(ModuleRecord::new(
            "C:/Games/Fallout 4/Data/Example.esl",
            ModuleKind::Light,
            ModuleHeaderVersion::Version100,
            true,
        ));
        installation
            .ini_files
            .fallout4
            .sections
            .entry("general".to_owned())
            .or_default()
            .insert("slanguage".to_owned(), "en".to_owned());

        assert_eq!(
            installation.archives[0].format.as_reference_magic(),
            Some("DX10")
        );
        assert_eq!(installation.archives[0].version.as_header_value(), 8);
        assert_eq!(
            installation.modules[0].header_version.as_reference_str(),
            Some("1.00")
        );
        assert_eq!(
            installation.ini_files.fallout4.get("general", "slanguage"),
            Some("en")
        );
    }

    #[test]
    fn install_type_and_semantic_version_reference_display_values_are_stable() {
        assert_eq!(Fallout4InstallType::OldGen.to_string(), "Old-Gen");
        assert_eq!(Fallout4InstallType::DownGrade.to_string(), "Down-Grade");
        assert_eq!(
            Fallout4InstallType::NextGenAnniversary.to_string(),
            "Next-Gen & Anniversary"
        );
        assert_eq!(Fallout4InstallType::NotFound.to_string(), "Not Found");
        assert_eq!(SemanticVersion::new(2, 5, 2).to_string(), "2.5.2");
        assert_eq!(SemanticVersion::zero().to_string(), "0.0.0");
    }

    #[test]
    fn discovery_not_found_error_is_recoverable_and_does_not_require_file_picker() {
        let error = DiscoveryError::fallout4_not_found(Some(
            "registry read failed: access denied to HKLM path".to_owned(),
        ));

        assert_eq!(error.kind, DiscoveryErrorKind::Fallout4NotFound);
        assert_eq!(
            error.user_message(),
            "A Fallout 4 installation could not be found."
        );
        assert!(error.is_recoverable());
        assert!(!error.requires_manual_file_picker());
        assert_eq!(
            error.diagnostic.as_deref(),
            Some("registry read failed: access denied to HKLM path")
        );
        assert!(!error.user_message().contains("HKLM"));
    }

    #[test]
    fn discovery_messages_keep_reference_path_exceptions() {
        let registry_error = DiscoveryError::invalid_registry_path("D:/Moved/Fallout 4");
        assert_eq!(
            registry_error.user_message(),
            "A Fallout 4 installation could not be found.\n\nThe path set in your registry is:\nD:/Moved/Fallout 4\n\nIf this is not correct, please run the Fallout 4 Launcher to correct it."
        );

        let known_folder_error =
            DiscoveryError::environment_folder_missing("C:/Users/Example/Documents");
        assert_eq!(
            known_folder_error.user_message(),
            "Folder does not exist:\nC:/Users/Example/Documents"
        );
    }

    #[test]
    fn tab_loading_error_messages_match_reference_text() {
        assert_eq!(
            DiscoveryError::data_folder_not_found().user_message(),
            "Data folder not found"
        );
        assert_eq!(
            DiscoveryError::f4se_plugins_folder_not_found(true).user_message(),
            "Data/F4SE/Plugins folder not found"
        );
        assert_eq!(
            DiscoveryError::f4se_plugins_folder_not_found(false).user_message(),
            "Data/F4SE/Plugins folder not found\nTry launching via your mod manager."
        );
    }
}

//! Pure domain contracts for mod-manager discovery results.
//!
//! The reference app detects Mod Organizer 2 and Vortex from process ancestry,
//! then only reads MO2 configuration. These contracts capture that scope without
//! performing process inspection, filesystem reads, or INI parsing themselves.

use std::{
    collections::{BTreeMap, BTreeSet},
    fmt,
    path::{Path, PathBuf},
};

use crate::domain::discovery::SemanticVersion;

/// Exact display names for supported mod managers.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
pub enum ModManagerKind {
    /// Mod Organizer 2, displayed by the reference as `Mod Organizer`.
    ModOrganizer,
    /// Vortex, detected but not deeply parsed by the reference app.
    Vortex,
}

impl ModManagerKind {
    /// Returns the exact reference display name.
    pub const fn display_name(self) -> &'static str {
        match self {
            Self::ModOrganizer => "Mod Organizer",
            Self::Vortex => "Vortex",
        }
    }

    /// Returns the executable name used by the reference process detection.
    pub const fn executable_name(self) -> &'static str {
        match self {
            Self::ModOrganizer => "ModOrganizer.exe",
            Self::Vortex => "Vortex.exe",
        }
    }
}

impl fmt::Display for ModManagerKind {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(self.display_name())
    }
}

/// A mod manager executable detected by platform adapters.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct DetectedModManager {
    /// Kind of manager detected.
    pub kind: ModManagerKind,
    /// Absolute or adapter-supplied executable path.
    pub executable_path: PathBuf,
    /// Three-part executable version, or `0.0.0` when unavailable.
    pub version: SemanticVersion,
}

impl DetectedModManager {
    /// Creates a detected manager from already-collected adapter data.
    pub fn new(
        kind: ModManagerKind,
        executable_path: impl Into<PathBuf>,
        version: SemanticVersion,
    ) -> Self {
        Self {
            kind,
            executable_path: executable_path.into(),
            version,
        }
    }

    /// Creates a Mod Organizer detection result.
    pub fn mod_organizer(executable_path: impl Into<PathBuf>, version: SemanticVersion) -> Self {
        Self::new(ModManagerKind::ModOrganizer, executable_path, version)
    }

    /// Creates a Vortex detection result with the reference `0.0.0` fallback.
    pub fn vortex(executable_path: impl Into<PathBuf>, version: Option<SemanticVersion>) -> Self {
        Self::new(
            ModManagerKind::Vortex,
            executable_path,
            version.unwrap_or_else(SemanticVersion::zero),
        )
    }

    /// Returns the exact reference display name for this manager.
    pub const fn display_name(&self) -> &'static str {
        self.kind.display_name()
    }

    /// Returns whether this manager has staging/config parsing in the reference scope.
    pub const fn has_staging_configuration_scope(&self) -> bool {
        matches!(self.kind, ModManagerKind::ModOrganizer)
    }
}

/// Context for Vortex detection.
///
/// The reference recognizes Vortex and displays a warning that it is not fully
/// supported. It does not parse staging folders or Vortex configuration, so this
/// type intentionally carries only the detected executable identity.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct VortexContext {
    /// Detected Vortex executable identity.
    pub manager: DetectedModManager,
}

impl VortexContext {
    /// Creates Vortex context with a `0.0.0` fallback when version metadata is absent.
    pub fn new(executable_path: impl Into<PathBuf>, version: Option<SemanticVersion>) -> Self {
        Self {
            manager: DetectedModManager::vortex(executable_path, version),
        }
    }

    /// Returns false because Vortex staging/config parsing is outside the reference scope.
    pub const fn parses_staging_or_config(&self) -> bool {
        false
    }
}

/// Tool executable categories read from MO2 custom executables.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum ModOrganizerTool {
    /// xEdit or FO4Edit executable.
    XEdit,
    /// BSArch executable inferred from xEdit folders or explicit entries.
    BSArch,
}

impl ModOrganizerTool {
    /// Returns the reference lowercase executable suffixes used for matching.
    pub const fn executable_suffixes(self) -> &'static [&'static str] {
        match self {
            Self::XEdit => &["xedit.exe", "fo4edit.exe"],
            Self::BSArch => &["bsarch.exe"],
        }
    }
}

/// Paths parsed from an MO2 configuration.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ModOrganizerDirectories {
    /// MO2 base directory used to expand `%BASE_DIR%` settings.
    pub base_directory: PathBuf,
    /// MO2 cache/webcache directory.
    pub cache_directory: PathBuf,
    /// MO2 downloads directory.
    pub download_directory: PathBuf,
    /// MO2 mods/staging directory.
    pub mod_directory: PathBuf,
    /// MO2 overwrite directory.
    pub overwrite_directory: PathBuf,
    /// MO2 profiles directory.
    pub profiles_directory: PathBuf,
}

impl ModOrganizerDirectories {
    /// Creates explicit MO2 directories from adapter-parsed values.
    pub fn new(
        base_directory: impl Into<PathBuf>,
        cache_directory: impl Into<PathBuf>,
        download_directory: impl Into<PathBuf>,
        mod_directory: impl Into<PathBuf>,
        overwrite_directory: impl Into<PathBuf>,
        profiles_directory: impl Into<PathBuf>,
    ) -> Self {
        Self {
            base_directory: base_directory.into(),
            cache_directory: cache_directory.into(),
            download_directory: download_directory.into(),
            mod_directory: mod_directory.into(),
            overwrite_directory: overwrite_directory.into(),
            profiles_directory: profiles_directory.into(),
        }
    }

    /// Creates the reference MO2 defaults relative to an already-known base directory.
    pub fn reference_defaults(base_directory: impl Into<PathBuf>) -> Self {
        let base_directory = base_directory.into();
        Self {
            cache_directory: base_directory.join("webcache"),
            download_directory: base_directory.join("downloads"),
            mod_directory: base_directory.join("mods"),
            overwrite_directory: base_directory.join("overwrite"),
            profiles_directory: base_directory.join("profiles"),
            base_directory,
        }
    }
}

/// Skip rules parsed from an MO2 configuration.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ModOrganizerSkipRules {
    /// Lowercase file suffixes to skip, defaulting to `.mohidden`.
    pub file_suffixes: Vec<String>,
    /// Lowercase directory names to skip.
    pub directories: BTreeSet<String>,
}

impl Default for ModOrganizerSkipRules {
    fn default() -> Self {
        Self {
            file_suffixes: vec![".mohidden".to_owned()],
            directories: BTreeSet::new(),
        }
    }
}

impl ModOrganizerSkipRules {
    /// Creates skip rules while normalizing suffixes and directory names to lowercase.
    pub fn new(
        file_suffixes: impl IntoIterator<Item = impl AsRef<str>>,
        directories: impl IntoIterator<Item = impl AsRef<str>>,
    ) -> Self {
        Self {
            file_suffixes: file_suffixes
                .into_iter()
                .map(|suffix| suffix.as_ref().to_lowercase())
                .collect(),
            directories: directories
                .into_iter()
                .map(|directory| directory.as_ref().to_lowercase())
                .collect(),
        }
    }
}

/// Parsed MO2 context needed by scanner and overview workflows.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ModOrganizerContext {
    /// Detected Mod Organizer executable identity.
    pub manager: DetectedModManager,
    /// Optional `ModOrganizer.ini` path used to create this context.
    pub ini_path: Option<PathBuf>,
    /// Optional `portable.txt` marker path when portable mode is detected.
    pub portable_txt_path: Option<PathBuf>,
    /// Whether MO2 portable mode was detected.
    pub portable: bool,
    /// Optional `gamePath` value from `[General]`.
    pub game_path: Option<PathBuf>,
    /// `selected_profile` value from `[General]`.
    pub selected_profile: String,
    /// Directory values parsed from `[Settings]`.
    pub directories: ModOrganizerDirectories,
    /// `profile_local_inis` value from `[Settings]`.
    pub profile_local_inis: bool,
    /// `profile_local_saves` value from `[Settings]`.
    pub profile_local_saves: bool,
    /// MO2 skip rules from `[Settings]`.
    pub skip_rules: ModOrganizerSkipRules,
}

impl ModOrganizerContext {
    /// Creates required MO2 context with reference defaults for optional flags and skip rules.
    pub fn new(
        manager: DetectedModManager,
        selected_profile: impl Into<String>,
        directories: ModOrganizerDirectories,
    ) -> Self {
        Self {
            manager,
            ini_path: None,
            portable_txt_path: None,
            portable: false,
            game_path: None,
            selected_profile: selected_profile.into(),
            directories,
            profile_local_inis: false,
            profile_local_saves: false,
            skip_rules: ModOrganizerSkipRules::default(),
        }
    }

    /// Adds the optional `gamePath` setting.
    pub fn with_game_path(mut self, game_path: impl Into<PathBuf>) -> Self {
        self.game_path = Some(game_path.into());
        self
    }

    /// Adds source INI and portable marker details.
    pub fn with_source_paths(
        mut self,
        ini_path: impl Into<Option<PathBuf>>,
        portable_txt_path: impl Into<Option<PathBuf>>,
        portable: bool,
    ) -> Self {
        self.ini_path = ini_path.into();
        self.portable_txt_path = portable_txt_path.into();
        self.portable = portable;
        self
    }

    /// Adds profile-local flag values parsed from MO2 settings.
    pub const fn with_profile_local_flags(mut self, local_inis: bool, local_saves: bool) -> Self {
        self.profile_local_inis = local_inis;
        self.profile_local_saves = local_saves;
        self
    }

    /// Adds normalized skip rules parsed from MO2 settings.
    pub fn with_skip_rules(mut self, skip_rules: ModOrganizerSkipRules) -> Self {
        self.skip_rules = skip_rules;
        self
    }

    /// Returns the MO2 mods/staging directory.
    pub fn mod_directory(&self) -> &Path {
        &self.directories.mod_directory
    }

    /// Returns the MO2 overwrite directory.
    pub fn overwrite_directory(&self) -> &Path {
        &self.directories.overwrite_directory
    }

    /// Returns the MO2 profiles directory.
    pub fn profiles_directory(&self) -> &Path {
        &self.directories.profiles_directory
    }
}

/// Complete parsed MO2 configuration result.
