        assert_eq!(path_problem.path.as_deref(), Some(Path::new("C:/Games/Fallout 4/Data/Broken.ba2")));
        assert_eq!(path_problem.relative_path.as_deref(), Some(Path::new("Broken.ba2")));
        assert_eq!(path_problem.problem.label(), "Invalid Archive");
        assert_eq!(path_problem.summary, "Archive is either corrupt or not in Bethesda Archive 2 format.");
        assert_eq!(path_problem.solution, None);
        assert_eq!(path_problem.details[0].value, "99");

        let pathless = OverviewProblem::pathless(
            OverviewProblemSource::CountLimit,
