        assert_eq!(archives.rows[4].value, 2);
        assert_eq!(archives.rows[5].value, 3);

        let modules = ModulePanelSummary::from_records(&[
            ModuleRecord::new(
                "C:/Games/Fallout 4/Data/Full.esp",
